BEGIN TRANSACTION;
CREATE TABLE "Allieve" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nome" varchar(100) NOT NULL, "cognome" varchar(100) NOT NULL, "data_nascita" date NULL, "telefono" varchar(20) NULL, "email" varchar(254) NULL, "data_iscrizione" date NULL, "certificato_medico" date NULL, "id_corso" bigint NULL REFERENCES "Corsi" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "Assegnazione_Costumi" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "pagato" bool NOT NULL, "consegnato" bool NOT NULL, "id_allieva" bigint NOT NULL REFERENCES "Allieve" ("id") DEFERRABLE INITIALLY DEFERRED, "id_coreografia" bigint NOT NULL REFERENCES "Coreografie" ("id") DEFERRABLE INITIALLY DEFERRED, "id_costume" bigint NOT NULL REFERENCES "Costumi" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "Competizione" ("id_concorso" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "classifica" integer NULL, "numero_giudici" integer NOT NULL);
CREATE TABLE "Coreografie" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nome" varchar(200) NOT NULL, "atto" integer NOT NULL, "ordine_uscita" integer NULL, "musica" varchar(200) NULL, "durata" integer NULL, "id_corso" bigint NULL REFERENCES "Corsi" ("id") DEFERRABLE INITIALLY DEFERRED, "id_maestra" bigint NULL REFERENCES "Maestre" ("id") DEFERRABLE INITIALLY DEFERRED, "id_saggio" bigint NOT NULL REFERENCES "Saggi" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "Corsi" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nome" varchar(150) NOT NULL, "livello" varchar(50) NULL, "fascia_eta" varchar(100) NULL, "id_maestra" bigint NULL REFERENCES "Maestre" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "Costumi" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nome" varchar(200) NOT NULL, "descrizione" text NULL, "taglia" varchar(10) NULL, "prezzo" decimal NULL, "fornitore" varchar(150) NULL, "stato_ordine" varchar(50) NOT NULL);
CREATE TABLE "Iscrizione_Competizione" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "id_allieva" bigint NOT NULL REFERENCES "Allieve" ("id") DEFERRABLE INITIALLY DEFERRED, "id_concorso" integer NOT NULL REFERENCES "Competizione" ("id_concorso") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "Lezioni" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "giorno_settimana" varchar(20) NOT NULL, "ora_inizio" time NOT NULL, "ora_fine" time NOT NULL, "sala" varchar(50) NULL, "id_corso" bigint NOT NULL REFERENCES "Corsi" ("id") DEFERRABLE INITIALLY DEFERRED, "id_maestra" bigint NULL REFERENCES "Maestre" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "Maestre" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nome" varchar(100) NOT NULL, "cognome" varchar(100) NOT NULL, "telefono" varchar(20) NULL, "email" varchar(254) NULL, "specializzazione" varchar(100) NULL, "compenso_mensile" decimal NULL);
CREATE TABLE "Pagamenti_Allieve" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "importo" decimal NOT NULL, "data_scadenza" date NOT NULL, "data_pagamento" date NULL, "stato" varchar(50) NOT NULL, "descrizione" varchar(200) NULL, "id_allieva" bigint NOT NULL REFERENCES "Allieve" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "Pagamenti_Maestre" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "importo" decimal NOT NULL, "data_scadenza" date NOT NULL, "data_pagamento" date NULL, "stato" varchar(50) NOT NULL, "descrizione" varchar(200) NULL, "id_maestra" bigint NOT NULL REFERENCES "Maestre" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "Saggi" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "titolo" varchar(200) NOT NULL, "data" date NULL, "luogo" varchar(200) NULL, "ora_inizio" time NULL, "stato" varchar(50) NOT NULL, "numero_atti" integer NOT NULL, "durata_totale" integer NOT NULL);
CREATE TABLE "auth_group" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(150) NOT NULL UNIQUE);
CREATE TABLE "auth_group_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "auth_permission" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "content_type_id" integer NOT NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "codename" varchar(100) NOT NULL, "name" varchar(255) NOT NULL);
CREATE TABLE "auth_user" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "password" varchar(128) NOT NULL, "last_login" datetime NULL, "is_superuser" bool NOT NULL, "username" varchar(150) NOT NULL UNIQUE, "last_name" varchar(150) NOT NULL, "email" varchar(254) NOT NULL, "is_staff" bool NOT NULL, "is_active" bool NOT NULL, "date_joined" datetime NOT NULL, "first_name" varchar(150) NOT NULL);
CREATE TABLE "auth_user_groups" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "auth_user_user_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "django_admin_log" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "object_id" text NULL, "object_repr" varchar(200) NOT NULL, "action_flag" smallint unsigned NOT NULL CHECK ("action_flag" >= 0), "change_message" text NOT NULL, "content_type_id" integer NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "action_time" datetime NOT NULL);
CREATE TABLE "django_content_type" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app_label" varchar(100) NOT NULL, "model" varchar(100) NOT NULL);
CREATE TABLE "django_migrations" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app" varchar(255) NOT NULL, "name" varchar(255) NOT NULL, "applied" datetime NOT NULL);
CREATE TABLE "django_session" ("session_key" varchar(40) NOT NULL PRIMARY KEY, "session_data" text NOT NULL, "expire_date" datetime NOT NULL);
